{
  "name": "Sales PDF Analyzer",
  "description": "An application that reads PDF sales reports using Gemini AI and visualizes the data on an interactive dashboard."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SaleItem {
  date: string;
  productName: string;
  category: string;
  quantity: number;
  unitPrice: number;
  totalPrice: number;
}

export interface AnalysisState {
  isLoading: boolean;
  error: string | null;
  data: SaleItem[];
  fileName: string | null;
}

export enum FileError {
  TOO_LARGE = "O arquivo é muito grande. O limite é 20MB.",
  INVALID_TYPE = "Tipo de arquivo inválido. Por favor envie um PDF.",
  READ_ERROR = "Erro ao ler o arquivo.",
  AI_ERROR = "Erro ao processar o PDF com a IA."
}

import { GoogleGenAI, Type } from "@google/genai";
import { SaleItem } from "../types";

const processFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      let encoded = reader.result?.toString().replace(/^data:(.*,)?/, "");
      if (encoded && (encoded.length % 4) > 0) {
        encoded += '='.repeat(4 - (encoded.length % 4));
      }
      resolve(encoded || "");
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeSalesPdf = async (file: File): Promise<SaleItem[]> => {
  try {
    const base64Data = await processFileToBase64(file);

    // We use gemini-2.5-flash-latest because it has excellent document understanding capabilities
    // and a large context window suitable for PDF reports.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-latest",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "application/pdf",
              data: base64Data
            }
          },
          {
            text: `Analise este documento PDF de vendas. Extraia todas as transações de venda encontradas em uma estrutura JSON limpa.

            Regras de extração:
            1. Ignore cabeçalhos repetitivos, rodapés ou texto de marketing.
            2. Se a data não tiver ano, assuma o ano atual.
            3. Normalize os nomes das categorias.
            4. Se houver tabela, extraia linha por linha.

            Retorne APENAS o JSON conforme o schema.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              date: { type: Type.STRING, description: "Data da venda no formato YYYY-MM-DD" },
              productName: { type: Type.STRING, description: "Nome do produto vendido" },
              category: { type: Type.STRING, description: "Categoria do produto (ex: Eletrônicos, Roupas)" },
              quantity: { type: Type.NUMBER, description: "Quantidade vendida" },
              unitPrice: { type: Type.NUMBER, description: "Preço unitário" },
              totalPrice: { type: Type.NUMBER, description: "Preço total (quantidade * unitário)" }
            },
            required: ["date", "productName", "category", "quantity", "unitPrice", "totalPrice"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) {
        throw new Error("Resposta vazia da IA");
    }

    const data = JSON.parse(text) as SaleItem[];
    return data;

  } catch (error) {
    console.error("Error analyzing PDF:", error);
    throw error;
  }
};

import React, { useRef, useState } from 'react';
import { UploadCloud, FileText, Loader2, AlertCircle } from 'lucide-react';

interface FileUploadProps {
  onFileSelect: (file: File) => void;
  isLoading: boolean;
  fileName: string | null;
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, isLoading, fileName }) => {
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      validateAndPass(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      validateAndPass(e.target.files[0]);
    }
  };

  const validateAndPass = (file: File) => {
    if (file.type !== "application/pdf") {
      alert("Por favor, envie apenas arquivos PDF.");
      return;
    }
    onFileSelect(file);
  };

  const triggerInput = () => {
    inputRef.current?.click();
  };

  return (
    <div className="w-full max-w-2xl mx-auto mb-8">
      <form
        className={`relative flex flex-col items-center justify-center w-full h-64 border-2 border-dashed rounded-xl transition-all duration-300 ease-in-out cursor-pointer
        ${dragActive ? "border-blue-500 bg-blue-50" : "border-gray-300 bg-white hover:bg-gray-50"}
        ${isLoading ? "opacity-75 pointer-events-none" : ""}
        `}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
        onClick={triggerInput}
      >
        <input
          ref={inputRef}
          type="file"
          className="hidden"
          accept="application/pdf"
          onChange={handleChange}
        />

        <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
          {isLoading ? (
            <>
              <Loader2 className="w-12 h-12 mb-4 text-blue-600 animate-spin" />
              <p className="mb-2 text-lg font-semibold text-gray-700">Analisando vendas...</p>
              <p className="text-sm text-gray-500">A IA está lendo seu PDF. Isso pode levar alguns segundos.</p>
            </>
          ) : fileName ? (
             <>
              <FileText className="w-12 h-12 mb-4 text-emerald-500" />
              <p className="mb-2 text-lg font-semibold text-gray-700">Arquivo Carregado</p>
              <p className="text-sm text-emerald-600 font-medium">{fileName}</p>
              <p className="mt-2 text-xs text-gray-400">Clique ou arraste para substituir</p>
            </>
          ) : (
            <>
              <UploadCloud className={`w-12 h-12 mb-4 ${dragActive ? "text-blue-500" : "text-gray-400"}`} />
              <p className="mb-2 text-lg font-semibold text-gray-700">
                <span className="font-bold">Clique para enviar</span> ou arraste o arquivo
              </p>
              <p className="text-sm text-gray-500">PDF (Relatórios de Vendas, Faturas, Extratos)</p>
            </>
          )}
        </div>
      </form>
    </div>
  );
};

import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  LineChart, Line, PieChart, Pie, Cell 
} from 'recharts';
import { SaleItem } from '../types';
import { TrendingUp, DollarSign, ShoppingCart, Package } from 'lucide-react';

interface DashboardProps {
  data: SaleItem[];
}

// Helper to format currency
const formatCurrency = (value: number) => 
  new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

export const Dashboard: React.FC<DashboardProps> = ({ data }) => {

  // -- Calculations --
  const stats = useMemo(() => {
    const totalRevenue = data.reduce((acc, item) => acc + item.totalPrice, 0);
    const totalItems = data.reduce((acc, item) => acc + item.quantity, 0);
    const totalOrders = data.length; // Assuming each row is a line item, rough approximation of orders or at least transactions
    const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

    return { totalRevenue, totalItems, totalOrders, averageOrderValue };
  }, [data]);

  const salesByCategory = useMemo(() => {
    const agg: Record<string, number> = {};
    data.forEach(item => {
      agg[item.category] = (agg[item.category] || 0) + item.totalPrice;
    });
    return Object.entries(agg)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value); // Sort desc
  }, [data]);

  const salesOverTime = useMemo(() => {
    const agg: Record<string, number> = {};
    data.forEach(item => {
      // Assuming ISO date YYYY-MM-DD
      const date = item.date; 
      agg[date] = (agg[date] || 0) + item.totalPrice;
    });
    return Object.entries(agg)
      .map(([date, total]) => ({ date, total }))
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [data]);

  const topProducts = useMemo(() => {
      const agg: Record<string, number> = {};
      data.forEach(item => {
          agg[item.productName] = (agg[item.productName] || 0) + item.quantity;
      });
      return Object.entries(agg)
        .map(([name, quantity]) => ({ name, quantity }))
        .sort((a, b) => b.quantity - a.quantity)
        .slice(0, 5);
  }, [data]);


  return (
    <div className="w-full max-w-7xl mx-auto px-4 pb-12 animate-fade-in">

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 flex items-center">
          <div className="p-3 rounded-full bg-blue-100 text-blue-600 mr-4">
            <DollarSign size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 font-medium">Receita Total</p>
            <h3 className="text-2xl font-bold text-gray-800">{formatCurrency(stats.totalRevenue)}</h3>
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 flex items-center">
          <div className="p-3 rounded-full bg-emerald-100 text-emerald-600 mr-4">
            <ShoppingCart size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 font-medium">Vendas Realizadas</p>
            <h3 className="text-2xl font-bold text-gray-800">{stats.totalOrders}</h3>
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 flex items-center">
          <div className="p-3 rounded-full bg-orange-100 text-orange-600 mr-4">
            <Package size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 font-medium">Itens Vendidos</p>
            <h3 className="text-2xl font-bold text-gray-800">{stats.totalItems}</h3>
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 flex items-center">
          <div className="p-3 rounded-full bg-purple-100 text-purple-600 mr-4">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 font-medium">Ticket Médio</p>
            <h3 className="text-2xl font-bold text-gray-800">{formatCurrency(stats.averageOrderValue)}</h3>
          </div>
        </div>
      </div>

      {/* Charts Row 1 */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">

        {/* Sales Over Time */}
        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Receita ao Longo do Tempo</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={salesOverTime} margin={{ top: 5, right: 20, bottom: 5, left: 0 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
                <XAxis dataKey="date" stroke="#94a3b8" tick={{fontSize: 12}} tickFormatter={(value) => new Date(value).toLocaleDateString('pt-BR', {day: '2-digit', month: '2-digit'})} />
                <YAxis stroke="#94a3b8" tick={{fontSize: 12}} tickFormatter={(value) => `R$${value/1000}k`} />
                <Tooltip 
                  formatter={(value: number) => [formatCurrency(value), 'Receita']}
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Line type="monotone" dataKey="total" stroke="#3b82f6" strokeWidth={3} dot={{r: 4, fill: '#3b82f6'}} activeDot={{ r: 8 }} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Sales by Category */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Vendas por Categoria</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={salesByCategory}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {salesByCategory.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => formatCurrency(value)} />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

       {/* Charts Row 2 */}
       <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
             <h3 className="text-lg font-bold text-gray-800 mb-6">Top 5 Produtos (Quantidade)</h3>
             <div className="h-80 w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={topProducts} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                    <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f0f0f0" />
                    <XAxis type="number" stroke="#94a3b8" />
                    <YAxis dataKey="name" type="category" width={100} stroke="#475569" tick={{fontSize: 11}} />
                    <Tooltip cursor={{fill: 'transparent'}} />
                    <Bar dataKey="quantity" fill="#10b981" radius={[0, 4, 4, 0]} barSize={20} />
                  </BarChart>
                </ResponsiveContainer>
             </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col">
            <h3 className="text-lg font-bold text-gray-800 mb-4">Resumo da IA</h3>
            <div className="flex-1 bg-blue-50 rounded-lg p-5">
                <p className="text-gray-700 leading-relaxed">
                    Com base nos dados extraídos do PDF, sua loja gerou um total de <span className="font-bold text-blue-700">{formatCurrency(stats.totalRevenue)}</span>. 
                    A categoria com melhor desempenho foi <span className="font-bold text-blue-700">{salesByCategory[0]?.name || 'N/A'}</span>. 
                    Houve um total de <span className="font-bold text-blue-700">{stats.totalOrders}</span> transações identificadas no período analisado.
                </p>
                <div className="mt-4 pt-4 border-t border-blue-100">
                    <p className="text-sm text-blue-600 font-semibold flex items-center gap-2">
                        <TrendingUp size={16} /> 
                        Insights gerados automaticamente
                    </p>
                </div>
            </div>
          </div>
       </div>

      {/* Recent Transactions Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100">
          <h3 className="text-lg font-bold text-gray-800">Transações Extraídas</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-600">
            <thead className="bg-gray-50 text-gray-800 font-semibold uppercase tracking-wider text-xs">
              <tr>
                <th className="px-6 py-4">Data</th>
                <th className="px-6 py-4">Produto</th>
                <th className="px-6 py-4">Categoria</th>
                <th className="px-6 py-4 text-right">Qtd</th>
                <th className="px-6 py-4 text-right">Preço Un.</th>
                <th className="px-6 py-4 text-right">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {data.map((item, index) => (
                <tr key={index} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4 whitespace-nowrap">{item.date}</td>
                  <td className="px-6 py-4 font-medium text-gray-900">{item.productName}</td>
                  <td className="px-6 py-4">
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                      {item.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">{item.quantity}</td>
                  <td className="px-6 py-4 text-right">{formatCurrency(item.unitPrice)}</td>
                  <td className="px-6 py-4 text-right font-medium text-gray-900">{formatCurrency(item.totalPrice)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {data.length === 0 && (
           <div className="p-8 text-center text-gray-500">
