import { GoogleGenAI, Type } from "@google/genai";
import { SaleItem } from "../types";

const processFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      let encoded = reader.result?.toString().replace(/^data:(.*,)?/, "");
      if (encoded && (encoded.length % 4) > 0) {
        encoded += '='.repeat(4 - (encoded.length % 4));
      }
      resolve(encoded || "");
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeSalesPdf = async (file: File): Promise<SaleItem[]> => {
  try {
    const base64Data = await processFileToBase64(file);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "application/pdf",
              data: base64Data
            }
          },
          {
            text: `Analise este relatório financeiro/de vendas em PDF. 
            Identifique a tabela que contém as seguintes colunas (ou variações delas):
            PEDIDO, VALOR, DESCONTO, ACRESCIMO, TOTAL, DINHEIRO, CHEQ-DIA, CHEQ-PRÉ, DÉBITO, CRÉDITO, MOV.BANCO, FATURADO, V.TROCA, S.RESERV, TOTAL CR/TR/CE.

            Extraia os dados linha a linha para um formato JSON.

            Regras importantes:
            1. Converta todos os valores monetários para números (ex: "1.000,00" vira 1000.00).
            2. Se a data não estiver explícita na linha, tente encontrá-la no cabeçalho do documento ou use a data de hoje.
            3. "orderId" deve ser o número do PEDIDO.
            4. Certifique-se de capturar corretamente os valores nas colunas de pagamento correspondentes.

            Retorne APENAS o JSON.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              orderId: { type: Type.STRING, description: "Número do Pedido (PEDIDO)" },
              date: { type: Type.STRING, description: "Data da transação (YYYY-MM-DD)" },

              value: { type: Type.NUMBER, description: "Valor Bruto (VALOR)" },
              discount: { type: Type.NUMBER, description: "Valor do Desconto (DESCONTO)" },
              surcharge: { type: Type.NUMBER, description: "Valor do Acréscimo (ACRESCIMO)" },
              total: { type: Type.NUMBER, description: "Valor Líquido Total (TOTAL)" },

              paymentCash: { type: Type.NUMBER, description: "Pagamento em Dinheiro (DINHEIRO)" },
              paymentCheckDay: { type: Type.NUMBER, description: "Pagamento Cheque à Vista (CHEQ-DIA)" },
              paymentCheckPre: { type: Type.NUMBER, description: "Pagamento Cheque Pré (CHEQ-PRÉ)" },
              paymentDebit: { type: Type.NUMBER, description: "Pagamento Cartão Débito (DÉBITO)" },
              paymentCredit: { type: Type.NUMBER, description: "Pagamento Cartão Crédito (CRÉDITO)" },
              paymentBank: { type: Type.NUMBER, description: "Pagamento Bancário/Pix (MOV.BANCO)" },
              paymentInvoiced: { type: Type.NUMBER, description: "Pagamento Faturado (FATURADO)" },
              paymentExchange: { type: Type.NUMBER, description: "Valor de Troca (V.TROCA)" },

              reserved: { type: Type.NUMBER, description: "S.RESERV" },
              totalCrTrCe: { type: Type.NUMBER, description: "TOTAL CR/TR/CE" }
            },
            required: ["orderId", "total", "value"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) {
        throw new Error("Resposta vazia da IA");
    }

    const data = JSON.parse(text) as SaleItem[];
    return data;

  } catch (error) {
    console.error("Error analyzing PDF:", error);
    throw error;
  }
};

