  new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

export const Dashboard: React.FC<DashboardProps> = ({ data }) => {

  // -- Calculations --
  const stats = useMemo(() => {
    const totalGross = data.reduce((acc, item) => acc + (item.value || 0), 0);
    const totalNet = data.reduce((acc, item) => acc + (item.total || 0), 0);
    const totalDiscount = data.reduce((acc, item) => acc + (item.discount || 0), 0);
    const totalSurcharge = data.reduce((acc, item) => acc + (item.surcharge || 0), 0);
    const totalOrders = data.length;
    const averageTicket = totalOrders > 0 ? totalNet / totalOrders : 0;

    return { totalGross, totalNet, totalDiscount, totalSurcharge, totalOrders, averageTicket };
  }, [data]);

  const paymentMethods = useMemo(() => {
    const methods = [
      { name: 'Dinheiro', key: 'paymentCash' },
      { name: 'Débito', key: 'paymentDebit' },
      { name: 'Crédito', key: 'paymentCredit' },
      { name: 'Mov. Banco', key: 'paymentBank' },
      { name: 'Cheque (Dia/Pré)', key: 'checkTotal' }, // Virtual key for aggregation
      { name: 'Faturado', key: 'paymentInvoiced' },
      { name: 'Troca', key: 'paymentExchange' },
    ];

    const dataPoints = methods.map(m => {
      const value = data.reduce((acc, item) => {
        if (m.key === 'checkTotal') {
          return acc + (item.paymentCheckDay || 0) + (item.paymentCheckPre || 0);
        }
        // @ts-ignore - indexing by key
        return acc + (item[m.key] || 0);
      }, 0);
      return { name: m.name, value };
    }).filter(p => p.value > 0).sort((a, b) => b.value - a.value);

    return dataPoints;
