                      <td className="px-4 py-3 text-right text-red-600">{item.discount > 0 ? `-${formatCurrency(item.discount)}` : '-'}</td>
                      <td className="px-4 py-3 text-right text-green-600">{item.surcharge > 0 ? `+${formatCurrency(item.surcharge)}` : '-'}</td>
                      <td className="px-4 py-3 text-right font-bold text-gray-900 bg-gray-50">{formatCurrency(item.total)}</td>

                      <td className="px-4 py-3 text-right text-gray-500">{item.paymentCash > 0 ? formatCurrency(item.paymentCash) : ''}</td>
                      <td className="px-4 py-3 text-right text-gray-500">{item.paymentDebit > 0 ? formatCurrency(item.paymentDebit) : ''}</td>
                      <td className="px-4 py-3 text-right text-gray-500">{item.paymentCredit > 0 ? formatCurrency(item.paymentCredit) : ''}</td>
                      <td className="px-4 py-3 text-right text-gray-500">{item.paymentBank > 0 ? formatCurrency(item.paymentBank) : ''}</td>
                      <td className="px-4 py-3 text-right text-gray-400">{others > 0 ? formatCurrency(others) : ''}</td>
                    </tr>
                  )
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

