export enum FileError {
  TOO_LARGE = "O arquivo é muito grande. O limite é 20MB.",
  INVALID_TYPE = "Tipo de arquivo inválido. Por favor envie um PDF.",
  READ_ERROR = "Erro ao ler o arquivo.",
  AI_ERROR = "Erro ao processar o PDF com a IA."
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const processFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      let encoded = reader.result?.toString().replace(/^data:(.*,)?/, "");
      if (encoded && (encoded.length % 4) > 0) {
        encoded += '='.repeat(4 - (encoded.length % 4));
      }
      resolve(encoded || "");
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeSalesPdf = async (file: File): Promise<AnalysisResult> => {
  try {
    const base64Data = await processFileToBase64(file);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "application/pdf",
              data: base64Data
            }
          },
          {
            text: `Analise este relatório de fechamento de caixa/vendas. Preciso extrair dois grupos de dados: a lista de vendas detalhada e o resumo financeiro do caixa.

            GRUPO 1: VENDAS (Lista)
            Extraia a tabela de vendas contendo: PEDIDO, VALOR, DESCONTO, ACRESCIMO, TOTAL, DINHEIRO, CHEQ-DIA, CHEQ-PRÉ, DÉBITO, CRÉDITO, MOV.BANCO, FATURADO, V.TROCA, S.RESERV, TOTAL CR/TR/CE.

            GRUPO 2: RESUMO FINANCEIRO E CAIXA (Campos específicos)
            Procure pelos seguintes totais e tabelas analíticas no rodapé ou resumo do documento:
            1. Total de Recebimento no Caixa (Soma das entradas efetivas no caixa físico).
            2. Receita Bruta (Soma total dos valores brutos).
            3. Receita Líquida (Soma total líquida).
            4. Previsão de Receita Futura (Geralmente soma de Crédito + Cheque Pré + Faturado).
            5. RELAÇÃO DE VENDA FATURADA (Lista de pedidos faturados).
            6. SUPRIMENTOS (Lista analítica de entradas/aportes no caixa).
            7. RETIRADAS (Lista analítica de sangrias/pagamentos feitos com o caixa).
            8. POSIÇÃO DO CAIXA (O saldo final: Entradas - Saídas).
            9. RECEBIMENTO DE DÉBITO ANTERIOR (Valores recebidos de dívidas antigas).

            Retorne um JSON contendo 'sales' (array) e 'summary' (objeto).
            Se algum campo numérico não for encontrado, retorne 0.
            `
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sales: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  orderId: { type: Type.STRING },
                  date: { type: Type.STRING },
                  value: { type: Type.NUMBER },
                  discount: { type: Type.NUMBER },
                  surcharge: { type: Type.NUMBER },
                  total: { type: Type.NUMBER },
                  paymentCash: { type: Type.NUMBER },
                  paymentCheckDay: { type: Type.NUMBER },
                  paymentCheckPre: { type: Type.NUMBER },
                  paymentDebit: { type: Type.NUMBER },
                  paymentCredit: { type: Type.NUMBER },
                  paymentBank: { type: Type.NUMBER },
                  paymentInvoiced: { type: Type.NUMBER },
                  paymentExchange: { type: Type.NUMBER },
                  reserved: { type: Type.NUMBER },
                  totalCrTrCe: { type: Type.NUMBER }
                },
                required: ["orderId", "total", "value"]
              }
            },
            summary: {
              type: Type.OBJECT,
              properties: {
                totalCashReceipts: { type: Type.NUMBER, description: "Total de Recebimento no Caixa" },
                grossRevenue: { type: Type.NUMBER, description: "Receita Bruta Total" },
                netRevenue: { type: Type.NUMBER, description: "Receita Líquida Total" },
                futureRevenueForecast: { type: Type.NUMBER, description: "Previsão de Receita Futura" },
                cashPosition: { type: Type.NUMBER, description: "Posição Final do Caixa" },
                previousDebitReceipts: { type: Type.NUMBER, description: "Recebimento de Débito Anterior" },
                supplies: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      description: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                withdrawals: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      description: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                invoicedSales: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      orderId: { type: Type.STRING },
                      customerName: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                }
              },
              required: ["totalCashReceipts", "grossRevenue", "netRevenue", "cashPosition"]
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) {
        throw new Error("Resposta vazia da IA");
    }

    const data = JSON.parse(text) as AnalysisResult;
    return data;

  } catch (error) {
    console.error("Error analyzing PDF:", error);
    throw error;
  }
};

