                 <table className="w-full text-sm">
                    <tbody className="divide-y divide-gray-100">
                       {data.summary.supplies.length > 0 ? data.summary.supplies.map((item, i) => (
                          <tr key={i}>
                             <td className="px-4 py-3 text-gray-600">{item.description}</td>
                             <td className="px-4 py-3 text-right font-medium text-emerald-600">+{formatCurrency(item.value)}</td>
                          </tr>
                       )) : (
                         <tr><td colSpan={2} className="px-4 py-6 text-center text-gray-400 italic">Nenhum suprimento registrado</td></tr>
                       )}
                    </tbody>
                 </table>
               </div>
            </div>

            {/* Withdrawals */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
               <div className="p-4 border-b border-gray-100 bg-red-50/50 flex justify-between items-center">
                  <h4 className="font-bold text-red-800 flex items-center gap-2">
                    <ArrowUpRight size={18} /> Retiradas (Analítico)
                  </h4>
               </div>
               <div className="overflow-x-auto">
                 <table className="w-full text-sm">
                    <tbody className="divide-y divide-gray-100">
                       {data.summary.withdrawals.length > 0 ? data.summary.withdrawals.map((item, i) => (
                          <tr key={i}>
                             <td className="px-4 py-3 text-gray-600">{item.description}</td>
                             <td className="px-4 py-3 text-right font-medium text-red-600">-{formatCurrency(item.value)}</td>
                          </tr>
                       )) : (
                         <tr><td colSpan={2} className="px-4 py-6 text-center text-gray-400 italic">Nenhuma retirada registrada</td></tr>
                       )}
                    </tbody>
                 </table>
               </div>
            </div>
          </div>

        </div>
      )}
    </div>
  );
};

// Sub-component for KPI Cards to reduce duplication
const KpiCard = ({ title, value, icon: Icon, color, isCurrency = true }: any) => {
  const colorClasses: any = {
    blue: 'bg-blue-50 text-blue-600',
    emerald: 'bg-emerald-50 text-emerald-600',
    red: 'bg-red-50 text-red-500',
    purple: 'bg-purple-50 text-purple-600'
  };

  return (
    <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 flex items-center justify-between">
      <div>
        <p className="text-sm text-gray-500 font-medium uppercase tracking-wide">{title}</p>
        <h3 className={`text-2xl font-bold mt-1 ${color === 'red' ? 'text-red-600' : 'text-gray-900'}`}>
          {isCurrency ? formatCurrency(value) : value}
        </h3>
      </div>
      <div className={`p-3 rounded-lg ${colorClasses[color]}`}>
        <Icon size={24} />
      </div>
    </div>
  );
};

