import React, { useMemo, useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  PieChart, Pie, Cell
} from 'recharts';
import { AnalysisResult } from '../types';
import { 
  TrendingUp, DollarSign, CreditCard, Receipt, Wallet, Percent, 
  LayoutDashboard, Scale, ArrowDownRight, ArrowUpRight, CalendarClock, Activity,
  BarChart3, PieChart as PieIcon
} from 'lucide-react';

interface DashboardProps {
  data: AnalysisResult;
}

// Helper to format currency
const formatCurrency = (value: number) => 
  new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

export const Dashboard: React.FC<DashboardProps> = ({ data }) => {
  const [activeTab, setActiveTab] = useState<'sales' | 'financial'>('sales');

  // -- Sales Calculations --
  const salesStats = useMemo(() => {
    const totalGross = data.sales.reduce((acc, item) => acc + (item.value || 0), 0);
    const totalNet = data.sales.reduce((acc, item) => acc + (item.total || 0), 0);
    const totalDiscount = data.sales.reduce((acc, item) => acc + (item.discount || 0), 0);
    const totalOrders = data.sales.length;
    const averageTicket = totalOrders > 0 ? totalNet / totalOrders : 0;

    return { totalGross, totalNet, totalDiscount, totalOrders, averageTicket };
  }, [data.sales]);

  const paymentMethods = useMemo(() => {
    const methods = [
      { name: 'Dinheiro', key: 'paymentCash' },
      { name: 'Débito', key: 'paymentDebit' },
      { name: 'Crédito', key: 'paymentCredit' },
      { name: 'Mov. Banco', key: 'paymentBank' },
      { name: 'Cheque', key: 'checkTotal' },
      { name: 'Faturado', key: 'paymentInvoiced' },
      { name: 'Troca', key: 'paymentExchange' },
    ];

    const dataPoints = methods.map(m => {
      const value = data.sales.reduce((acc, item) => {
        if (m.key === 'checkTotal') {
          return acc + (item.paymentCheckDay || 0) + (item.paymentCheckPre || 0);
        }
        // @ts-ignore
        return acc + (item[m.key] || 0);
      }, 0);
      return { name: m.name, value };
    }).filter(p => p.value > 0).sort((a, b) => b.value - a.value);

    return dataPoints;
  }, [data.sales]);

  // -- Financial Calculations --
  const financialCharts = useMemo(() => {
    const suppliesTotal = data.summary.supplies.reduce((acc, item) => acc + item.value, 0);
    const withdrawalsTotal = data.summary.withdrawals.reduce((acc, item) => acc + item.value, 0);
    const totalReceipts = data.summary.totalCashReceipts + data.summary.previousDebitReceipts;

    const cashFlow = [
      { name: 'Entradas', value: totalReceipts, fill: '#10b981' }, // Emerald
      { name: 'Suprimentos', value: suppliesTotal, fill: '#3b82f6' }, // Blue
      { name: 'Retiradas', value: withdrawalsTotal, fill: '#ef4444' }, // Red
      { name: 'Saldo Final', value: data.summary.cashPosition, fill: '#8b5cf6' }, // Violet
    ];

    const revenueDistribution = [
      { name: 'Em Caixa', value: data.summary.totalCashReceipts, fill: '#10b981' },
      { name: 'A Receber', value: data.summary.futureRevenueForecast, fill: '#f59e0b' },
    ].filter(i => i.value > 0);

    return { cashFlow, revenueDistribution };
  }, [data.summary]);

  return (
    <div className="w-full max-w-[1600px] mx-auto px-4 pb-12 animate-fade-in">

      {/* Tabs Navigation */}
      <div className="flex justify-center mb-8">
        <div className="bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-gray-100 dark:border-slate-700 inline-flex transition-colors">
          <button
            onClick={() => setActiveTab('sales')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'sales' 
                ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-50 dark:hover:bg-slate-700'
            }`}
          >
            <LayoutDashboard size={18} />
            Análise de Vendas
          </button>
          <button
            onClick={() => setActiveTab('financial')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'financial' 
                ? 'bg-emerald-50 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-50 dark:hover:bg-slate-700'
            }`}
          >
            <Scale size={18} />
            Fechamento de Caixa
          </button>
        </div>
      </div>

      {activeTab === 'sales' ? (
        /* SALES DASHBOARD */
        <div className="space-y-6 animate-fade-in">
          {/* KPI Cards */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <KpiCard title="Faturamento Líquido" value={salesStats.totalNet} icon={DollarSign} color="blue" />
            <KpiCard title="Pedidos" value={salesStats.totalOrders} icon={Receipt} color="emerald" isCurrency={false} />
            <KpiCard title="Total Descontos" value={salesStats.totalDiscount} icon={Percent} color="red" />
            <KpiCard title="Ticket Médio" value={salesStats.averageTicket} icon={TrendingUp} color="purple" />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Payment Methods Chart */}
            <div className="lg:col-span-2 bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-gray-100 dark:border-slate-700 transition-colors">
              <h3 className="text-lg font-bold text-gray-800 dark:text-white flex items-center gap-2 mb-6">
                <Wallet className="w-5 h-5 text-gray-500 dark:text-gray-400" /> Formas de Pagamento
              </h3>
              <div className="h-80 w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={paymentMethods} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" strokeOpacity={0.5} />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} dy={10} />
                    <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} tickFormatter={(val) => `R$${val/1000}k`} />
                    <Tooltip 
                        cursor={{fill: 'rgba(255,255,255,0.1)'}} 
                        formatter={(value: number) => [formatCurrency(value), 'Valor']} 
                        contentStyle={{ 
                            borderRadius: '8px', 
                            border: 'none', 
                            boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)',
                            backgroundColor: 'rgba(15, 23, 42, 0.95)',
                            color: '#fff'
                        }} 
                        itemStyle={{ color: '#fff' }}
                    />
                    <Bar dataKey="value" radius={[6, 6, 0, 0]} barSize={50}>
                      {paymentMethods.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Distribution Pie Chart */}
            <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-gray-100 dark:border-slate-700 transition-colors">
              <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-6 flex items-center gap-2">
                <CreditCard className="w-5 h-5 text-gray-500 dark:text-gray-400" /> Distribuição
              </h3>
              <div className="h-80 w-full relative">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie data={paymentMethods} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                      {paymentMethods.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip formatter={(value: number) => formatCurrency(value)} contentStyle={{ backgroundColor: 'rgba(15, 23, 42, 0.95)', border: 'none', borderRadius: '8px', color: '#fff' }} />
                    <Legend verticalAlign="bottom" height={36}/>
                  </PieChart>
                </ResponsiveContainer>
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                  <div className="text-center">
                    <p className="text-xs text-gray-500 dark:text-gray-400">Total</p>
                    <p className="font-bold text-gray-800 dark:text-white">{formatCurrency(salesStats.totalNet)}</p>
                  </div>
                </div>
