import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const processFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      let encoded = reader.result?.toString().replace(/^data:(.*,)?/, "");
      if (encoded && (encoded.length % 4) > 0) {
        encoded += '='.repeat(4 - (encoded.length % 4));
      }
      resolve(encoded || "");
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeSalesPdf = async (file: File, apiKey: string): Promise<AnalysisResult> => {
  try {
    if (!apiKey) {
        throw new Error("API Key não fornecida.");
    }

    const base64Data = await processFileToBase64(file);

    const ai = new GoogleGenAI({ apiKey: apiKey });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: "application/pdf",
              data: base64Data
            }
          },
          {
            text: `Extraia os dados de vendas deste PDF. Seja extremamente preciso e retorne APENAS o JSON.

            REGRAS:
            1. No array 'sales', inclua cada venda individual encontrada. Se houver muitas, não omita nenhuma.
            2. No objeto 'summary', extraia os totais financeiros.
            3. Use 0 para valores não encontrados.
            4. Certifique-se de que o JSON esteja COMPLETO e bem formatado.
            5. Remova quaisquer caracteres especiais de quebra de linha dentro de strings de texto para não quebrar o JSON.

            Campos de Venda: PEDIDO (orderId), VALOR (value), DESCONTO (discount), TOTAL (total).
            Campos de Resumo: Receita Bruta, Receita Líquida, Posição do Caixa, Suprimentos e Retiradas.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sales: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  orderId: { type: Type.STRING },
                  date: { type: Type.STRING },
                  value: { type: Type.NUMBER },
                  discount: { type: Type.NUMBER },
                  surcharge: { type: Type.NUMBER },
                  total: { type: Type.NUMBER },
                  paymentCash: { type: Type.NUMBER },
                  paymentCheckDay: { type: Type.NUMBER },
                  paymentCheckPre: { type: Type.NUMBER },
                  paymentDebit: { type: Type.NUMBER },
                  paymentCredit: { type: Type.NUMBER },
                  paymentBank: { type: Type.NUMBER },
                  paymentInvoiced: { type: Type.NUMBER },
                  paymentExchange: { type: Type.NUMBER },
                  reserved: { type: Type.NUMBER },
                  totalCrTrCe: { type: Type.NUMBER }
                },
                required: ["orderId", "total"]
              }
            },
            summary: {
              type: Type.OBJECT,
              properties: {
                totalCashReceipts: { type: Type.NUMBER },
                grossRevenue: { type: Type.NUMBER },
                netRevenue: { type: Type.NUMBER },
                futureRevenueForecast: { type: Type.NUMBER },
                cashPosition: { type: Type.NUMBER },
                previousDebitReceipts: { type: Type.NUMBER },
                supplies: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      description: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                withdrawals: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      description: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                invoicedSales: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      orderId: { type: Type.STRING },
                      customerName: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                }
              },
              required: ["grossRevenue", "netRevenue", "cashPosition"]
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) {
        throw new Error("A IA retornou uma resposta vazia.");
    }

    try {
      return JSON.parse(text) as AnalysisResult;
    } catch (parseError) {
      console.error("Erro ao fazer parse do JSON:", text);
      throw new Error("Os dados retornados pela IA estão incompletos ou malformados. Tente um arquivo menor ou com menos páginas.");
    }

  } catch (error) {
    console.error("Error analyzing PDF:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { FileUpload } from './components/FileUpload';
import { Dashboard } from './components/Dashboard';
import { analyzeSalesPdf } from './services/geminiService';
