  BarChart3, AlertTriangle, Moon, Sun, Menu, Settings, X, 
  ExternalLink, Key, Lock, CheckCircle2 
} from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    isLoading: false,
    error: null,
    data: null,
    fileName: null
  });

  // -- API KEY MANAGEMENT --
  const [apiKey, setApiKey] = useState<string>('');
  const [tempApiKey, setTempApiKey] = useState<string>('');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMissingKeyAlertOpen, setIsMissingKeyAlertOpen] = useState(false);

  // Load key from localStorage or env on mount
  useEffect(() => {
    const storedKey = localStorage.getItem('gemini_api_key');
    const envKey = process.env.API_KEY; // Fallback to env if available
    const initialKey = storedKey || envKey || '';

    setApiKey(initialKey);
    setTempApiKey(initialKey);
  }, []);

  const handleSaveApiKey = () => {
    if (tempApiKey.trim()) {
      localStorage.setItem('gemini_api_key', tempApiKey.trim());
      setApiKey(tempApiKey.trim());
      setIsSettingsOpen(false);
      setIsMissingKeyAlertOpen(false); // Close alert if open
    }
  };

  const handleRemoveApiKey = () => {
    localStorage.removeItem('gemini_api_key');
    setApiKey('');
    setTempApiKey('');
  };

  // -- DARK MODE --
  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const savedTheme = localStorage.getItem('theme');
      if (savedTheme) {
        return savedTheme === 'dark';
      }
      return window.matchMedia('(prefers-color-scheme: dark)').matches;
    }
    return false;
  });

  useEffect(() => {
    const html = document.documentElement;
    if (isDarkMode) {
      html.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      html.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
  };

  // -- MENU --
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);


  // -- HANDLERS --
  const handleFileSelect = async (file: File) => {
    // 1. Check API Key
    if (!apiKey) {
      setIsMissingKeyAlertOpen(true);
      return;
    }

    setState(prev => ({ ...prev, isLoading: true, error: null, fileName: file.name }));

    try {
      // 2. Pass apiKey to service
      const result = await analyzeSalesPdf(file, apiKey);
      setState(prev => ({ 
        ...prev, 
        isLoading: false, 
        data: result,
        error: (!result.sales || result.sales.length === 0) ? "Nenhuma venda foi identificada no PDF. Verifique se o arquivo está correto." : null
      }));
    } catch (error: any) {
      console.error("Erro completo:", error);

      let errorMessage = "Ocorreu um erro inesperado.";

      if (error.message?.includes("403") || error.message?.includes("API key")) {
        errorMessage = "Chave de API inválida ou expirada. Verifique suas configurações.";
        setIsSettingsOpen(true);
      } else if (error.message?.includes("JSON") || error.message?.includes("parse")) {
        errorMessage = "A resposta da IA foi interrompida ou está malformada. Tente um arquivo com menos páginas.";
      } else if (error.message) {
        errorMessage = error.message;
      }

      setState(prev => ({ 
        ...prev, 
        isLoading: false, 
        error: errorMessage 
      }));
    }
  };

  const handleReset = () => {
      setState({
          isLoading: false,
          error: null,
          data: null,
          fileName: null
      });
  }

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 flex flex-col transition-colors duration-300">

      {/* --- SETTINGS MODAL --- */}
