import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const processFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      let encoded = reader.result?.toString().replace(/^data:(.*,)?/, "");
      if (encoded && (encoded.length % 4) > 0) {
        encoded += '='.repeat(4 - (encoded.length % 4));
      }
      resolve(encoded || "");
    };
    reader.onerror = (error) => reject(error);
  });
};

export const analyzeSalesPdf = async (file: File, apiKey: string): Promise<AnalysisResult> => {
  try {
    if (!apiKey) throw new Error("API Key não fornecida.");

    const base64Data = await processFileToBase64(file);
    const ai = new GoogleGenAI({ apiKey: apiKey });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { mimeType: "application/pdf", data: base64Data } },
          {
            text: `Aja como um extrator de dados financeiro. Analise o PDF e retorne um JSON estrito.
            REGRAS CRÍTICAS:
            1. NÃO adicione markdown (como \`\`\`json).
            2. NÃO quebre a string de texto com 'newlines' dentro de valores.
            3. Se houver muitos registros, foque em extrair todos os itens da tabela de vendas principal.
            4. Se um valor numérico não existir, use 0.

            Extraia:
            - 'sales': Array de objetos com orderId, total, value, discount.
            - 'summary': Totais de grossRevenue, netRevenue, cashPosition, supplies (descrição/valor), withdrawals (descrição/valor).`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sales: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  orderId: { type: Type.STRING },
                  value: { type: Type.NUMBER },
                  discount: { type: Type.NUMBER },
                  total: { type: Type.NUMBER },
                  paymentMethod: { type: Type.STRING }
                },
                required: ["orderId", "total"]
              }
            },
            summary: {
              type: Type.OBJECT,
              properties: {
                grossRevenue: { type: Type.NUMBER },
                netRevenue: { type: Type.NUMBER },
                cashPosition: { type: Type.NUMBER },
                futureRevenueForecast: { type: Type.NUMBER },
                totalCashReceipts: { type: Type.NUMBER },
                previousDebitReceipts: { type: Type.NUMBER },
                supplies: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      description: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                withdrawals: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      description: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                invoicedSales: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      orderId: { type: Type.STRING },
                      customerName: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                }
              },
              required: ["grossRevenue", "netRevenue", "cashPosition"]
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Resposta vazia da IA.");

    try {
      return JSON.parse(text) as AnalysisResult;
    } catch (e) {
      console.error("JSON Error:", text);
      throw new Error("Erro na estrutura de dados da IA. Tente reenviar o arquivo.");
    }
  } catch (error) {
    console.error("Analysis Error:", error);
    throw error;
  }
};

