import { AnalysisState } from './types';
import { 
  BarChart3, AlertTriangle, Moon, Sun, Menu, Settings, X, 
  ExternalLink, Key, Lock, CheckCircle2, AlertOctagon 
} from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    isLoading: false,
    error: null,
    data: null,
    fileName: null
  });

  // -- API KEY MANAGEMENT --
  const [apiKey, setApiKey] = useState<string>('');
  const [tempApiKey, setTempApiKey] = useState<string>('');
  const [keyValidationMsg, setKeyValidationMsg] = useState<string | null>(null);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMissingKeyAlertOpen, setIsMissingKeyAlertOpen] = useState(false);

  // Load key from localStorage or env on mount
  useEffect(() => {
    const storedKey = localStorage.getItem('gemini_api_key');
    const envKey = process.env.API_KEY; // Fallback to env if available
    const initialKey = storedKey || envKey || '';

    setApiKey(initialKey);
    setTempApiKey(initialKey);
  }, []);

  const validateKeyFormat = (key: string): boolean => {
    // Basic Google API Key validation: Starts with AIza and has reasonable length
    if (!key) return false;
    return key.trim().startsWith('AIza') && key.trim().length > 35;
  };

  const handleSaveApiKey = () => {
    const cleanKey = tempApiKey.trim();

    if (!cleanKey) {
      setKeyValidationMsg("A chave não pode estar vazia.");
      return;
    }

    if (!validateKeyFormat(cleanKey)) {
      setKeyValidationMsg("O formato da chave parece inválido. Chaves do Google geralmente começam com 'AIza'.");
      return;
    }

    localStorage.setItem('gemini_api_key', cleanKey);
    setApiKey(cleanKey);
    setKeyValidationMsg(null);
    setIsSettingsOpen(false);
    setIsMissingKeyAlertOpen(false);
  };

  const handleRemoveApiKey = () => {
    localStorage.removeItem('gemini_api_key');
    setApiKey('');
    setTempApiKey('');
    setKeyValidationMsg(null);
  };

  // -- DARK MODE --
  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const savedTheme = localStorage.getItem('theme');
      if (savedTheme) {
        return savedTheme === 'dark';
      }
      return window.matchMedia('(prefers-color-scheme: dark)').matches;
    }
    return false;
  });

  useEffect(() => {
    const html = document.documentElement;
    if (isDarkMode) {
      html.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      html.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
  };

  // -- MENU --
