                    properties: {
                      description: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
                },
                withdrawals: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      description: { type: Type.STRING },
                      value: { type: Type.NUMBER }
                    }
                  }
