export const initializeFinancialChat = (data: AnalysisResult): Chat => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Convertemos os dados para string para dar contexto ao modelo
  const contextData = JSON.stringify({
    resumo: data.summary,
    totalVendas: data.sales.length,
    amostraVendas: data.sales.slice(0, 20) // Envia apenas as primeiras 20 para economizar tokens se a lista for gigante, mas o resumo já ajuda muito
  });

  return ai.chats.create({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `Você é um Consultor Financeiro Sênior chamado "FinBot". 
      Você tem acesso aos dados financeiros do usuário (JSON abaixo).

      DADOS DO RELATÓRIO:
      ${contextData}

      SUA MISSÃO:
      1. Fornecer insights sobre saúde financeira, fluxo de caixa e performance de vendas.
      2. Responder perguntas específicas como "Qual foi o ticket médio?", "Qual método de pagamento é mais usado?".
      3. Se a posição de caixa for negativa, dê alertas e sugestões.
      4. Seja conciso, profissional e use formatação Markdown (negrito, listas) para facilitar a leitura.
      5. Responda sempre em Português do Brasil.
      `,
    },
  });
};

import React, { useState, useEffect, useRef } from 'react';
import { MessageSquare, Send, X, Bot, Sparkles, Loader2, Minimize2, Maximize2 } from 'lucide-react';
import { AnalysisResult } from '../types';
import { initializeFinancialChat } from '../services/geminiService';
import { Chat, GenerateContentResponse } from "@google/genai";

interface FinancialAssistantProps {
  data: AnalysisResult;
}

interface Message {
  role: 'user' | 'model';
  text: string;
}

export const FinancialAssistant: React.FC<FinancialAssistantProps> = ({ data }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [chat, setChat] = useState<Chat | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Inicializa o chat quando os dados mudam
  useEffect(() => {
    if (data) {
      const chatInstance = initializeFinancialChat(data);
      setChat(chatInstance);
      setMessages([{
        role: 'model',
        text: 'Olá! Sou seu assistente financeiro. Analisei os dados do seu relatório. Posso destacar os pontos principais ou responder suas dúvidas. O que gostaria de saber?'
      }]);
    }
  }, [data]);

  // Auto-scroll para a última mensagem
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isOpen]);

  const handleSendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputText.trim() || !chat) return;

    const userMsg = inputText;
    setInputText('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const resultStream = await chat.sendMessageStream({ message: userMsg });

      let fullResponse = "";
      setMessages(prev => [...prev, { role: 'model', text: '' }]);

      for await (const chunk of resultStream) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          fullResponse += c.text;
          setMessages(prev => {
            const newHistory = [...prev];
            newHistory[newHistory.length - 1] = { role: 'model', text: fullResponse };
            return newHistory;
          });
        }
      }
    } catch (error) {
      console.error("Chat error", error);
      setMessages(prev => [...prev, { role: 'model', text: 'Desculpe, tive um problema ao processar sua pergunta. Tente novamente.' }]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleQuickPrompt = (prompt: string) => {
    setInputText(prompt);
    // Pequeno timeout para permitir que o estado atualize antes de enviar (opcional, mas bom para UX)
    setTimeout(() => {
       // Idealmente chamaria handleSendMessage diretamente, mas precisamos que o state inputText esteja atualizado se usarmos ele dentro do handler.
       // Vamos passar o texto diretamente para evitar dependência de estado assíncrono.
       if(chat) {
           setInputText(''); 
           setMessages(prev => [...prev, { role: 'user', text: prompt }]);
           setIsTyping(true);
           (async () => {
               try {
                   const resultStream = await chat.sendMessageStream({ message: prompt });
                   let fullResponse = "";
                   setMessages(prev => [...prev, { role: 'model', text: '' }]);
                   for await (const chunk of resultStream) {
                       const c = chunk as GenerateContentResponse;
                       if(c.text) {
                           fullResponse += c.text;
                           setMessages(prev => {
                               const newHistory = [...prev];
                               newHistory[newHistory.length - 1] = { role: 'model', text: fullResponse };
                               return newHistory;
                           });
                       }
                   }
               } catch(err) {
                   setMessages(prev => [...prev, { role: 'model', text: 'Erro ao analisar.' }]);
               } finally {
                   setIsTyping(false);
               }
           })();
       }
    }, 50);
  };

  if (!isOpen) {
    return (
      <button
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 z-40 bg-blue-600 hover:bg-blue-700 text-white p-4 rounded-full shadow-2xl transition-all transform hover:scale-110 flex items-center gap-2 animate-in fade-in slide-in-from-bottom-10"
      >
        <Sparkles size={24} />
        <span className="font-bold hidden md:inline">Assistente Financeiro</span>
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 z-50 w-[90vw] md:w-[400px] h-[600px] max-h-[80vh] bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-gray-200 dark:border-slate-700 flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">

      {/* Header */}
      <div className="bg-blue-600 p-4 flex items-center justify-between text-white shrink-0">
        <div className="flex items-center gap-2">
          <div className="bg-white/20 p-2 rounded-lg">
            <Bot size={20} />
          </div>
          <div>
            <h3 className="font-bold text-sm">FinBot Assistente</h3>
            <p className="text-xs text-blue-100 flex items-center gap-1">
              <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span> Online
            </p>
          </div>
        </div>
        <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-1 rounded transition-colors">
          <Minimize2 size={18} />
        </button>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 dark:bg-slate-900 scrollbar-thin scrollbar-thumb-gray-300 dark:scrollbar-thumb-slate-600">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] rounded-2xl p-3 text-sm leading-relaxed whitespace-pre-wrap ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : 'bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-slate-800 dark:text-slate-200 rounded-bl-none shadow-sm'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
             <div className="bg-white dark:bg-slate-800 p-3 rounded-2xl rounded-bl-none border border-gray-200 dark:border-slate-700 shadow-sm flex items-center gap-1">
                <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></span>
                <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></span>
                <span className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></span>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Quick Prompts */}
      {messages.length < 3 && !isTyping && (
         <div className="px-4 pb-2 bg-slate-50 dark:bg-slate-900 flex gap-2 overflow-x-auto no-scrollbar shrink-0">
            <button onClick={() => handleQuickPrompt("Resuma a saúde financeira")} className="whitespace-nowrap px-3 py-1.5 bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 text-xs rounded-full hover:bg-blue-200 transition-colors">
               📊 Resumo Geral
            </button>
            <button onClick={() => handleQuickPrompt("Quais os riscos atuais?")} className="whitespace-nowrap px-3 py-1.5 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300 text-xs rounded-full hover:bg-red-200 transition-colors">
               ⚠️ Riscos
            </button>
            <button onClick={() => handleQuickPrompt("Sugira melhorias")} className="whitespace-nowrap px-3 py-1.5 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300 text-xs rounded-full hover:bg-emerald-200 transition-colors">
               💡 Melhorias
            </button>
         </div>
      )}

      {/* Input Area */}
      <form onSubmit={handleSendMessage} className="p-3 bg-white dark:bg-slate-800 border-t border-gray-200 dark:border-slate-700 flex gap-2 shrink-0">
        <input
          type="text"
          value={inputText}
          onChange={(e) => setInputText(e.target.value)}
          placeholder="Pergunte sobre seus dados..."
          className="flex-1 bg-gray-100 dark:bg-slate-700 border-0 rounded-xl px-4 text-sm focus:ring-2 focus:ring-blue-500 dark:text-white outline-none"
        />
        <button 
          type="submit" 
          disabled={!inputText.trim() || isTyping}
          className="bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed text-white p-3 rounded-xl transition-colors"
        >
          {isTyping ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
        </button>
      </form>
    </div>
  );
};

