        ...prev, 
        isLoading: false, 
        data: result,
        error: (!result.sales || result.sales.length === 0) ? "Nenhuma venda foi identificada no PDF. Verifique se o arquivo está correto." : null
      }));
    } catch (error: any) {
      console.error("Erro completo:", error);

      let errorMessage = "Ocorreu um erro inesperado.";

      if (error.message?.includes("403") || error.message?.includes("API key")) {
        errorMessage = "Chave de API inválida ou expirada. Verifique suas configurações de ambiente.";
      } else if (error.message?.includes("JSON") || error.message?.includes("parse")) {
        errorMessage = "A resposta da IA foi interrompida ou está malformada. Tente um arquivo com menos páginas.";
      } else if (error.message) {
        errorMessage = error.message;
      }

      setState(prev => ({ 
        ...prev, 
        isLoading: false, 
        error: errorMessage 
      }));
    }
  };

  const handleReset = () => {
      setState({
          isLoading: false,
          error: null,
          data: null,
          fileName: null
      });
  }

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 flex flex-col transition-colors duration-300">

