          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 py-8">

        {state.error && (
            <div className="max-w-2xl mx-auto mb-6 p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg flex items-start gap-3 animate-fade-in">
